// src/pages/AdminCourses.js
import React, { useEffect, useState } from 'react';
import api from '../services/api';
import { adminService } from '../services/admin';

// ─── Pending Courses tab ──────────────────────────────────────────────────────
const PendingCoursesTab = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/courses/admin/courses/pending/')
      .then((res) => setCourses(res.data.results ?? res.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleApprove = async (id) => {
    try {
      await adminService.approveCourse(id);
      setCourses((prev) => prev.filter((c) => c.id !== id));
    } catch {
      alert('فشل الموافقة');
    }
  };

  const handleReject = async (id) => {
    try {
      await adminService.rejectCourse(id);
      setCourses((prev) => prev.filter((c) => c.id !== id));
    } catch {
      alert('فشل الرفض');
    }
  };

  if (loading) return <p style={s.msg}>Loading...</p>;
  if (!courses.length) return <p style={s.msg}>لا يوجد كورسات معلّقة 🎉</p>;

  return (
    <table style={s.table}>
      <thead>
        <tr>
          <th style={s.th}>العنوان</th>
          <th style={s.th}>المُدرّس</th>
          <th style={s.th}>السعر</th>
          <th style={s.th}>الإجراءات</th>
        </tr>
      </thead>
      <tbody>
        {courses.map((c) => (
          <tr key={c.id} style={s.tr}>
            <td style={s.td}>{c.title}</td>
            <td style={s.td}>{c.instructor_name || c.instructor_email}</td>
            <td style={s.td}>{c.price} EGP</td>
            <td style={s.td}>
              <button style={{ ...s.btn, ...s.approve }} onClick={() => handleApprove(c.id)}>✔ موافقة</button>
              <button style={{ ...s.btn, ...s.reject }}  onClick={() => handleReject(c.id)}>✖ رفض</button>
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  );
};

// ─── Pending Lectures tab ─────────────────────────────────────────────────────
const PendingLecturesTab = () => {
  const [lectures, setLectures] = useState([]);
  const [loading, setLoading]   = useState(true);

  useEffect(() => {
    api.get('/courses/admin/lectures/pending/')
      .then((res) => setLectures(res.data.results ?? res.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleAction = async (id, action) => {
    try {
      await api.patch(`/courses/admin/lectures/${id}/approve/`, { action });
      setLectures((prev) => prev.filter((l) => l.id !== id));
    } catch {
      alert('فشل الإجراء');
    }
  };

  if (loading) return <p style={s.msg}>Loading...</p>;
  if (!lectures.length) return <p style={s.msg}>لا يوجد فيديوهات معلّقة 🎉</p>;

  return (
    <table style={s.table}>
      <thead>
        <tr>
          <th style={s.th}>عنوان الليكتشر</th>
          <th style={s.th}>الكورس</th>
          <th style={s.th}>S3 Key</th>
          <th style={s.th}>الإجراءات</th>
        </tr>
      </thead>
      <tbody>
        {lectures.map((l) => (
          <tr key={l.id} style={s.tr}>
            <td style={s.td}>{l.title}</td>
            <td style={s.td}>{l.course?.title}</td>
            <td style={s.td}>
              <code style={{ fontSize: 11, wordBreak: 'break-all' }}>{l.s3_key}</code>
            </td>
            <td style={s.td}>
              <button style={{ ...s.btn, ...s.approve }} onClick={() => handleAction(l.id, 'approve')}>✔ موافقة</button>
              <button style={{ ...s.btn, ...s.reject }}  onClick={() => handleAction(l.id, 'reject')}>✖ رفض</button>
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  );
};

// ─── Main Page ────────────────────────────────────────────────────────────────
const AdminCourses = () => {
  const [tab, setTab] = useState('courses'); // 'courses' | 'lectures'

  return (
    <div style={s.page}>
      <div style={s.card}>
        <h2 style={s.title}>🛡️ لوحة الأدمن</h2>

        {/* Tabs */}
        <div style={s.tabs}>
          <button
            style={{ ...s.tabBtn, ...(tab === 'courses' ? s.tabActive : {}) }}
            onClick={() => setTab('courses')}
          >
            📚 كورسات معلّقة
          </button>
          <button
            style={{ ...s.tabBtn, ...(tab === 'lectures' ? s.tabActive : {}) }}
            onClick={() => setTab('lectures')}
          >
            🎬 فيديوهات معلّقة
          </button>
        </div>

        {tab === 'courses'  && <PendingCoursesTab />}
        {tab === 'lectures' && <PendingLecturesTab />}
      </div>
    </div>
  );
};

// ─── Styles ───────────────────────────────────────────────────────────────────
const s = {
  page:  { background: '#f4f6f8', minHeight: '100vh', padding: '40px 20px' },
  card:  { background: '#fff', borderRadius: 12, padding: 25,
           boxShadow: '0 10px 25px rgba(0,0,0,0.08)' },
  title: { marginBottom: 20 },
  tabs:  { display: 'flex', gap: 10, marginBottom: 20 },
  tabBtn: { padding: '9px 20px', borderRadius: 8, border: '1px solid #ccc',
            background: '#f0f0f0', cursor: 'pointer', fontWeight: 500 },
  tabActive: { background: '#007bff', color: '#fff', border: '1px solid #007bff' },
  msg:   { textAlign: 'center', color: '#999', padding: '30px 0' },
  table: { width: '100%', borderCollapse: 'collapse' },
  th:    { textAlign: 'left', padding: 12, borderBottom: '2px solid #eee', color: '#555', fontSize: 13 },
  tr:    { borderBottom: '1px solid #f0f0f0' },
  td:    { padding: '10px 12px', fontSize: 14 },
  btn:   { padding: '7px 14px', borderRadius: 6, border: 'none', cursor: 'pointer',
           marginRight: 8, fontWeight: 500, fontSize: 13 },
  approve: { backgroundColor: '#28a745', color: '#fff' },
  reject:  { backgroundColor: '#dc3545', color: '#fff' },
};

export default AdminCourses;
